#include <stdio.h>
#include <math.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld",&N);
        long long x = N-1;
        long long cnt = 0;
        long long i;
        for(i=1;i*i<=x;++i){
            if(x%i==0){
                if(i*i==x) cnt+=1; else cnt+=2;
            }
        }
        printf("%lld\n",cnt);
    }
    return 0;
}

