#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        long long N; cin>>N;
        long long x = N-1;
        long long cnt = 0;
        for(long long i=1;i*i<=x;++i){
            if(x%i==0){
                cnt += (i*i==x) ? 1 : 2;
            }
        }
        cout<<cnt<<"\n";
    }
    return 0;
}

